mapper.select:
SELECT id, tenant_id, email, display_name, is_default, created_at
FROM TENANT_SENDER
WHERE tenant_id = #{tenantId} AND email = #{email}

mapper.insert:
INSERT INTO TENANT_SENDER (tenant_id, email, display_name, is_default, created_at)
VALUES (#{tenantId}, #{email}, #{displayName}, #{isDefault}, CURRENT_TIMESTAMP)
ON CONFLICT (tenant_id, email) DO UPDATE SET display_name = #{displayName}, is_default = #{isDefault}
